SELECT [Sales Header].[Salesperson Code], Salesperson_Purchaser.Name AS SalespersonName, [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[Ship-to City], [Sales Header].No_ AS OrderNo, [Geographical Zone].Description AS GeographicalZone1_Description, [Geographical Zone_1].description AS GeographicalZone2Description, [Sales Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Header].[selling season code] AS Stagione, Item.[LINE CODE], Item.[COLLECTION CODE], Item.DESCRIPTION, Item.[DESCRIPTION 2], [Sales Line].[MODEL ITEM NO_], [Sales Line].[variable CODE 02] AS [size], [Sales Line].[VARIABLE CODE 01] AS COLOR, [Variable Code].Description AS ColorDecription, Item.[PRODUCT SEX], Val([quantity]) AS qty, IIf([Sales Line.document type]=1,(Val([Line Amount])-Val([Inv_ Discount Amount])),-(Val([Line Amount])-Val([Inv_ Discount Amount]))) AS ValueSold, [Sales Line].[DELETE REASON], [DB Suole BePositive].[CODICE SUOLA], [DB Suole BePositive].[COLORE SUOLA]
FROM (((((([Sales Header] INNER JOIN (Item INNER JOIN [Sales Line] ON Item.No_ = [Sales Line].No_) ON ([Sales Header].[Document Type] = [Sales Line].[Document Type]) AND ([Sales Header].No_ = [Sales Line].[Document No_])) LEFT JOIN [Sales Header Extension] ON [Sales Header].No_ = [Sales Header Extension].[Document No_]) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) LEFT JOIN [Geographical Zone] ON [Sales Header].[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON [Sales Header Extension].[Geographical Zone 2] = [Geographical Zone_1].Code) LEFT JOIN [Variable Code] ON ([Sales Line].[Variable Group 01] = [Variable Code].[Variable Group]) AND ([Sales Line].[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN [DB Suole BePositive] ON ([Sales Line].[Variable Code 01] = [DB Suole BePositive].Color) AND ([Sales Line].[Model Item No_] = [DB Suole BePositive].[Model Item No_])
WHERE ((([Sales Header].[Shortcut Dimension 2 Code])=[forms]![principale]![filtromarchiosourcing]) AND (([Sales Header].[selling season code])=[forms]![principale]![filtroStagionesourcing]) AND (([Sales Line].Type)=2));

